class Solution {
public:
    vector<int> maxScoreIndices(vector<int>& nums) {
        vector<int> result;
        for (int i = 0; i < nums.size(); i++) {
            int leftScore = 0;
            int rightScore = 0;
            if (nums[i] == 0) {
                for (int j = 0; j < i; j++) {
                    if (nums[j] == 0) {
                        leftScore += nums[j];
                    }
            }
            if (nums[i] == 1) {
                for (int j = i - 1; j >= 0; j--) {
                    if (nums[j] == 1) {
                        rightScore += nums[j];
                    }
            }
            result.push_back(max(leftScore, rightScore));
        }
        return result;
    }
}
